@pytest.mark.parametrize("amount,step_up,sufficient,exp_status,exp_code", [
    ("100.00", False, True, 202, None),
    ("10000.00", False, True, 202, None),
    ("10001.00", False, True, 422, "STEP_UP_REQUIRED"),
    ("10001.00", True, True, 202, None),
    ("100.00", False, False, 409, "INSUFFICIENT_FUNDS"),
])
def test_ach_transfer_decision_table_all_rules(ach_client, dt_account_fixture, amount, step_up, sufficient, exp_status, exp_code):
    account = dt_account_fixture(sufficient=sufficient)
    payload = {
        "source_account_id": account["account_id"],
        "destination_routing": account["routing"],
        "destination_account": account["external_account"],
        "amount": amount,
        "currency": "USD"
    }
    headers = {"X-Step-Up-Token": account["stepup_token"]} if step_up else {}
    resp = ach_client.post("/transfers/ach", json=payload, headers=headers)
    assert resp.status_code == exp_status
    if exp_code:
        body = resp.json()
        assert body["error"]["code"] == exp_code
